import React, { useState, useRef } from 'react';

const FoodDetectionApp = () => {
  const [currentMode, setCurrentMode] = useState('home');
  const [currentImage, setCurrentImage] = useState(null);
  const [imageFile, setImageFile] = useState(null);
  const [detectionResults, setDetectionResults] = useState(null);
  const [ocrResults, setOcrResults] = useState('');
  const [geminiResults, setGeminiResults] = useState('');
  const [fridgeIngredients, setFridgeIngredients] = useState([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [confidence, setConfidence] = useState(0.5);
  const [statusMessage, setStatusMessage] = useState('해먹기 또는 사먹기를 선택하세요.');
  const [isDragOver, setIsDragOver] = useState(false);
  const [activeTab, setActiveTab] = useState('detection');
  
  const fileInputRef = useRef(null);

  // API 기본 URL 설정
  const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || 'http://192.168.0.19:8000';

  // 기본 아이콘 컴포넌트들
  const CookingIcon = () => <span className="text-2xl">👨‍🍳</span>;
  const EatingIcon = () => <span className="text-2xl">🍽️</span>;
  const CameraIcon = () => <span className="text-lg">📷</span>;
  const UploadIcon = () => <span className="text-sm">📁</span>;
  const EyeIcon = () => <span className="text-sm">👁️</span>;
  const BrainIcon = () => <span className="text-sm">🧠</span>;
  const FileTextIcon = () => <span className="text-sm">📄</span>;
  const SettingsIcon = () => <span className="text-sm">⚙️</span>;
  const FridgeIcon = () => <span className="text-lg">🧊</span>;
  const BackIcon = () => <span className="text-sm">←</span>;
  const PlusIcon = () => <span className="text-sm">+</span>;
  const MinusIcon = () => <span className="text-sm">-</span>;
  const DeleteIcon = () => <span className="text-sm">🗑️</span>;
  const LoadingSpinner = () => (
    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
  );

  // 식재료 수량 업데이트 함수
  const updateIngredientQuantity = (id, newQuantity) => {
    if (newQuantity < 0) return;
    
    setFridgeIngredients(prev => 
      prev.map(ingredient => 
        ingredient.id === id 
          ? { ...ingredient, quantity: newQuantity }
          : ingredient
      )
    );
  };

  // 식재료 삭제 함수
  const removeIngredient = (id) => {
    setFridgeIngredients(prev => 
      prev.filter(ingredient => ingredient.id !== id)
    );
  };

  // 새로운 식재료를 기존 냉장고에 병합하는 함수 - 강화된 디버깅
  const mergeIngredientsToFridge = (newIngredients) => {
    if (!newIngredients || newIngredients.length === 0) {
      console.log('⚠️ 추가할 식재료가 없습니다.');
      return;
    }

    console.log('\n🔄 === 병합 시작 ===');
    console.log('🆕 새로 추가할 식재료:', newIngredients.map(item => `${item.name}:${item.quantity}개`));
    
    setFridgeIngredients(currentFridge => {
      console.log('📦 병합 시점의 실제 냉장고 상태:', currentFridge.map(item => `${item.name}:${item.quantity}개`));
      
      const newFridge = [...currentFridge];
      let maxId = newFridge.length > 0 ? Math.max(...newFridge.map(item => item.id)) : 0;

      newIngredients.forEach((newItem, index) => {
        console.log(`\n🔍 처리 중인 신규 식재료 ${index + 1}: "${newItem.name}" ${newItem.quantity}개`);
        
        const normalizedNewName = newItem.name.toLowerCase().replace(/\s+/g, '').trim();
        const existingIndex = newFridge.findIndex(item => {
          const normalizedExistingName = item.name.toLowerCase().replace(/\s+/g, '').trim();
          const isMatch = normalizedExistingName === normalizedNewName;
          console.log(`  🔍 비교: "${item.name}" vs "${newItem.name}" = ${isMatch}`);
          return isMatch;
        });

        if (existingIndex >= 0) {
          const oldQuantity = newFridge[existingIndex].quantity;
          const addQuantity = newItem.quantity;
          const finalQuantity = oldQuantity + addQuantity;
          
          console.log(`📈 기존 식재료 "${newFridge[existingIndex].name}" 수량 업데이트:`);
          console.log(`   기존 수량: ${oldQuantity}개`);
          console.log(`   추가 수량: +${addQuantity}개`);
          console.log(`   최종 수량: ${finalQuantity}개`);
          
          newFridge[existingIndex] = {
            ...newFridge[existingIndex],
            quantity: finalQuantity
          };
        } else {
          const newId = ++maxId;
          console.log(`➕ 새로운 식재료 추가: "${newItem.name}" ${newItem.quantity}개 (ID: ${newId})`);
          
          newFridge.push({
            id: newId,
            name: newItem.name,
            quantity: newItem.quantity,
            source: newItem.source || 'unknown',
            confidence: newItem.confidence || 0.8
          });
        }
      });

      console.log('✅ 병합 완료 - 최종 냉장고:', newFridge.map(item => `${item.name}:${item.quantity}개`));
      console.log(`📊 총 ${newFridge.length}개 종류, 총 ${newFridge.reduce((sum, item) => sum + item.quantity, 0)}개 식재료`);
      console.log('🔄 === 병합 종료 ===\n');
      
      return newFridge;
    });
  };

  // 홈으로 돌아가기
  const goToHome = () => {
    setCurrentMode('home');
    setCurrentImage(null);
    setImageFile(null);
    setDetectionResults(null);
    setOcrResults('');
    setGeminiResults('');
    setStatusMessage('해먹기 또는 사먹기를 선택하세요.');
    setActiveTab('detection');
  };

  // 해먹기 모드 시작
  const startHomeCooking = () => {
    setCurrentMode('homeCooking');
    setStatusMessage('냉장고 속 식재료 이미지를 업로드하세요.');
  };

  // 사먹기 모드 시작
  const startEating = () => {
    setCurrentMode('eating');
    setStatusMessage('사먹기 기능은 개발 중입니다.');
  };

  // 드래그 앤 드롭 핸들러
  const handleDragOver = (e) => {
    e.preventDefault();
    setIsDragOver(true);
  };

  const handleDragLeave = (e) => {
    e.preventDefault();
    setIsDragOver(false);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setIsDragOver(false);
    
    const files = e.dataTransfer.files;
    if (files.length > 0) {
      const file = files[0];
      if (file.type.startsWith('image/')) {
        console.log('🎯 드롭된 파일 처리:', file.name);
        processImageFile(file);
      } else {
        setStatusMessage('이미지 파일만 업로드 가능합니다.');
      }
    }
  };

  // 이미지 파일 처리 함수
  const processImageFile = (file) => {
    console.log('📁 === 이미지 파일 처리 시작 ===');
    console.log('📁 파일명:', file.name);
    
    setImageFile(file);
    
    if (!file.type.startsWith('image/')) {
      setStatusMessage('이미지 파일만 업로드 가능합니다.');
      return;
    }
    
    const reader = new FileReader();
    reader.onload = (e) => {
      console.log('🖼️ 이미지 로드 완료:', file.name);
      setCurrentImage(e.target.result);
      
      setDetectionResults(null);
      setOcrResults('');
      setGeminiResults('');
      setStatusMessage(`이미지 준비 완료: ${file.name} - "식재료 분석" 버튼을 클릭하세요`);
      
      console.log('✅ 이미지 로드 완료 - 분석 대기 중');
      console.log('📁 === 이미지 파일 처리 완료 ===\n');
    };
    
    reader.onerror = (e) => {
      console.error('❌ 이미지 로드 실패:', e);
      setStatusMessage('이미지 로드 실패');
    };
    
    reader.readAsDataURL(file);
  };

  // 이미지 로드 함수
  const handleImageLoad = (event) => {
    const file = event.target.files[0];
    if (file) {
      console.log('📁 파일 선택됨:', file.name, file.type, file.size);
      processImageFile(file);
    }
  };

  // 식재료 분석 실행 - 강화된 디버깅 버전
  const runIngredientAnalysis = async () => {
    console.log('\n🔔 === 사용자가 분석 버튼 클릭 ===');
    
    if (!imageFile) {
      setStatusMessage('먼저 이미지를 로드하세요.');
      console.log('❌ 이미지 파일이 없음');
      return;
    }

    if (isProcessing) {
      console.log('⚠️ 이미 분석 중입니다. 중복 실행 방지');
      return;
    }

    console.log('🚀 분석 시작 - 현재 냉장고 상태:', fridgeIngredients.map(item => `${item.name}:${item.quantity}개`));
    
    setIsProcessing(true);
    let allDetections = [];
    let extractedText = '';

    try {
      // 🎭 즉시 Mock 분석으로 시작 (테스트용)
      console.log('🎭 === Mock 분석 모드로 시작 ===');
      setProcessingStep('Mock AI 분석 중...');
      setStatusMessage('Mock AI 분석 중...');
      
      // Mock 탐지 결과 생성
      allDetections = [
        { class: 'apple', confidence: 0.85 },
        { class: 'banana', confidence: 0.92 },
        { class: 'carrot', confidence: 0.78 },
        { class: 'tomato', confidence: 0.83 },
        { class: 'onion', confidence: 0.76 }
      ];
      
      console.log('🎭 Mock 탐지 결과 생성:', allDetections);
      setDetectionResults({ detections: allDetections });
      
      // Mock OCR 결과
      extractedText = '사과 바나나 당근';
      setOcrResults(extractedText);
      
      // 1초 대기 (실제 분석 시뮬레이션)
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      // Mock Gemini 분석 결과
      const mockGeminiResult = '사과 2개\n바나나 1개\n당근 3개\n토마토 1개\n양파 2개';
      setGeminiResults(mockGeminiResult);
      
      console.log('🎭 Mock Gemini 분석 결과:', mockGeminiResult);
      
      // Mock 결과를 직접 파싱하여 냉장고에 추가
      const mockIngredients = [
        { id: Date.now() + 1, name: '사과', quantity: 2, source: 'mock_analysis', confidence: 0.85 },
        { id: Date.now() + 2, name: '바나나', quantity: 1, source: 'mock_analysis', confidence: 0.92 },
        { id: Date.now() + 3, name: '당근', quantity: 3, source: 'mock_analysis', confidence: 0.78 },
        { id: Date.now() + 4, name: '토마토', quantity: 1, source: 'mock_analysis', confidence: 0.83 },
        { id: Date.now() + 5, name: '양파', quantity: 2, source: 'mock_analysis', confidence: 0.76 }
      ];
      
      console.log('🎭 생성된 Mock 식재료:', mockIngredients);
      
      // 냉장고에 직접 추가
      console.log('📦 냉장고 업데이트 전 상태:', fridgeIngredients.map(item => `${item.name}:${item.quantity}개`));
      mergeIngredientsToFridge(mockIngredients);
      
      setStatusMessage(`Mock 분석 완료: ${mockIngredients.length}개 식재료 추가됨`);
      setActiveTab('gemini');
      
      console.log('✅ Mock 분석 완료');

      /* 실제 서버 분석 코드 (주석 처리)
      // 1단계: YOLO 탐지
      setProcessingStep('식품 탐지 중...');
      setStatusMessage('식품 탐지 중...');

      console.log('🔍 YOLO 탐지 시작');
      
      const detectFormData = new FormData();
      detectFormData.append('file', imageFile);
      detectFormData.append('confidence', confidence);

      const detectUrl = `${API_BASE_URL}/api/detect`;

      const detectResponse = await fetch(detectUrl, {
        method: 'POST',
        body: detectFormData,
      });

      if (detectResponse.ok) {
        const detectResult = await detectResponse.json();
        console.log('✅ YOLO 탐지 결과:', detectResult);
        setDetectionResults(detectResult);
        allDetections = detectResult.detections || [];
      } else {
        console.error('❌ YOLO 탐지 실패:', detectResponse.status);
        setDetectionResults({ detections: [] });
        // 탐지 실패해도 Mock 데이터로 계속 진행
        allDetections = [
          { class: 'apple', confidence: 0.85 },
          { class: 'banana', confidence: 0.92 },
          { class: 'carrot', confidence: 0.78 }
        ];
        console.log('🔄 Mock 데이터로 계속 진행:', allDetections);
      }

      // 2단계: OCR 텍스트 추출
      setProcessingStep('텍스트 추출 중...');
      
      const ocrFormData = new FormData();
      ocrFormData.append('file', imageFile);
      const ocrUrl = `${API_BASE_URL}/api/ocr`;

      try {
        const ocrResponse = await fetch(ocrUrl, {
          method: 'POST',
          body: ocrFormData,
        });

        if (ocrResponse.ok) {
          const ocrResult = await ocrResponse.json();
          console.log('✅ OCR 결과:', ocrResult);
          extractedText = ocrResult.text || '';
          setOcrResults(extractedText || '추출된 텍스트가 없습니다.');
        } else {
          console.warn('⚠️ OCR 실패, 계속 진행');
          setOcrResults('OCR 추출 실패');
        }
      } catch (ocrError) {
        console.warn('⚠️ OCR 오류, 계속 진행:', ocrError);
        setOcrResults('OCR 추출 실패');
      }

      // 3단계: Gemini 분석
      const hasOcrText = extractedText && extractedText.trim().length > 2;
      const hasDetections = allDetections && allDetections.length > 0;

      if (hasOcrText) {
        console.log('📄 OCR 텍스트 발견 - OCR 우선 분석');
        await analyzeOCRWithGemini(extractedText);
        setActiveTab('ocr');
      } else if (hasDetections) {
        console.log('🎯 OCR 없음, Detection 결과 분석');
        await analyzeDetectionWithGemini(allDetections);
        setActiveTab('detection');
      } else {
        // 탐지 결과가 없으면 Mock 분석 진행
        console.log('⚠️ 탐지 결과 없음 - Mock 분석 진행');
        await performMockAnalysis();
        setActiveTab('gemini');
      }
      */

    } catch (error) {
      console.error('❌ 식재료 분석 오류:', error);
      setStatusMessage(`식재료 분석 오류: ${error.message}`);
      
      // 오류 발생 시에도 Mock 분석 진행
      console.log('🔄 오류 발생 - Mock 분석으로 복구');
      await performMockAnalysis();
    } finally {
      setIsProcessing(false);
      setProcessingStep('');
      console.log('🏁 === 분석 완료 ===\n');
      
      // 최종 냉장고 상태 확인
      setTimeout(() => {
        console.log('📦 최종 냉장고 상태 확인:', fridgeIngredients.map(item => `${item.name}:${item.quantity}개`));
      }, 100);
    }
  };

  // Mock 분석 수행 (서버 연결 실패 시 대안) - 강화된 버전
  const performMockAnalysis = async () => {
    setProcessingStep('Mock AI 분석 중...');
    setStatusMessage('Mock AI 분석 중...');
    
    console.log('🎭 === Mock 분석 시작 ===');
    
    // 1초 대기 (실제 분석 시뮬레이션)
    await new Promise(resolve => setTimeout(resolve, 1000));
    
    const mockIngredients = [
      { id: Date.now() + 1, name: '사과', quantity: 2, source: 'mock_analysis', confidence: 0.85 },
      { id: Date.now() + 2, name: '바나나', quantity: 1, source: 'mock_analysis', confidence: 0.92 },
      { id: Date.now() + 3, name: '당근', quantity: 3, source: 'mock_analysis', confidence: 0.78 },
      { id: Date.now() + 4, name: '토마토', quantity: 1, source: 'mock_analysis', confidence: 0.83 }
    ];
    
    setGeminiResults('Mock 분석 결과:\n사과 2개\n바나나 1개\n당근 3개\n토마토 1개');
    
    console.log('🎭 Mock 분석으로 생성된 식재료:', mockIngredients);
    console.log('📦 Mock 분석 전 냉장고 상태:', fridgeIngredients.length, '개');
    
    // 강제로 냉장고에 추가 (mergeIngredientsToFridge 우회)
    setFridgeIngredients(prevIngredients => {
      console.log('📦 현재 냉장고:', prevIngredients.map(item => `${item.name}:${item.quantity}개`));
      
      const newFridge = [...prevIngredients];
      let maxId = newFridge.length > 0 ? Math.max(...newFridge.map(item => item.id)) : 0;

      mockIngredients.forEach(newItem => {
        const existingIndex = newFridge.findIndex(item => 
          item.name.toLowerCase() === newItem.name.toLowerCase()
        );

        if (existingIndex >= 0) {
          newFridge[existingIndex].quantity += newItem.quantity;
          console.log(`📈 기존 "${newItem.name}" 수량 증가: +${newItem.quantity}개`);
        } else {
          newFridge.push({
            ...newItem,
            id: maxId + newFridge.length + 1
          });
          console.log(`➕ 새로운 "${newItem.name}" 추가: ${newItem.quantity}개`);
        }
      });
      
      console.log('✅ Mock 분석 후 냉장고:', newFridge.map(item => `${item.name}:${item.quantity}개`));
      return newFridge;
    });
    
    setStatusMessage(`Mock AI 분석 완료: ${mockIngredients.length}개 식재료 추가됨`);
    console.log('🎭 === Mock 분석 완료 ===');
  };

  // OCR 결과를 Gemini로 분석하여 식재료 추론
  const analyzeOCRWithGemini = async (extractedText) => {
    setProcessingStep('AI가 OCR 텍스트에서 식재료를 추론 중...');
    setStatusMessage('AI가 OCR 텍스트에서 식재료를 추론 중...');

    console.log('🧠 Gemini OCR 분석 시작');
    console.log('📄 분석할 OCR 텍스트:', extractedText);

    try {
      const geminiUrl = `${API_BASE_URL}/api/analyze`;

      const analysisData = {
        text: extractedText,
        analysis_type: 'ocr_ingredient_analysis',
        prompt: `다음은 OCR로 추출된 텍스트입니다. 이 텍스트를 분석하여 정확한 식재료나 음식 제품명을 추론해주세요.

OCR 텍스트: "${extractedText}"

중요한 구분 규칙:
1. 과일 vs 주스 구분:
   - "오렌지" 단독 = 과일 오렌지
   - "오렌지 + JUICE/주스/과즙" = 오렌지주스

2. 과일 vs 우유 구분:
   - "바나나" 단독 = 과일 바나나
   - "바나나 + 우유/MILK" = 바나나우유

3. 가공 여부 판단 키워드:
   - 주스 관련: JUICE, 주스, 과즙, 농축, 100%, mL, L
   - 우유 관련: MILK, 우유, 음료, 라떼

4. 용량/브랜드 제거:
   - 용량: 210mL, 1L, 500g 등 제거
   - 브랜드: PREMIUM, FRESH, 냉장제품 등 제거

출력 형식:
오렌지주스 1개
사과 2개

위 OCR 텍스트를 분석하여 정확한 제품명을 추론해주세요:`
      };

      const geminiResponse = await fetch(geminiUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(analysisData),
      });

      if (geminiResponse.ok) {
        const geminiResult = await geminiResponse.json();
        console.log('✅ Gemini OCR 분석 결과:', geminiResult);
        
        const analysisText = geminiResult.analysis || '분석 결과가 없습니다.';
        setGeminiResults(analysisText);

        const newIngredients = parseGeminiOCRAnalysis(analysisText);
        console.log('📄 OCR 분석으로 추출된 최종 식재료:', newIngredients);
        
        if (newIngredients.length > 0) {
          mergeIngredientsToFridge(newIngredients);
          setStatusMessage(`OCR AI 분석 완료: ${newIngredients.length}개 식재료 추가`);
        } else {
          setStatusMessage('OCR AI 분석 완료: 추출된 식재료 없음');
        }
      } else {
        throw new Error('Gemini OCR 분석 실패');
      }
    } catch (error) {
      console.error('❌ Gemini OCR 분석 오류:', error);
      setGeminiResults('OCR AI 분석 실패 - Mock 데이터로 대체');
      
      // 실패 시 Mock 데이터 사용
      const mockIngredients = [
        { name: '우유', quantity: 1, source: 'ocr_mock', confidence: 0.8 },
        { name: '오렌지주스', quantity: 1, source: 'ocr_mock', confidence: 0.8 }
      ];
      mergeIngredientsToFridge(mockIngredients);
      setStatusMessage('OCR 분석 실패 - Mock 데이터 추가됨');
    }
  };

  // Gemini로 Detection 결과 분석하여 한글 식재료명 변환
  const analyzeDetectionWithGemini = async (detections) => {
    setProcessingStep('AI가 탐지 결과를 식재료로 변환 중...');
    setStatusMessage('AI가 탐지 결과를 식재료로 변환 중...');

    console.log('🧠 Gemini Detection 분석 시작');

    try {
      const geminiUrl = `${API_BASE_URL}/api/analyze`;
      
      const detectionList = detections.map(d => 
        `${d.class} (정확도: ${(d.confidence * 100).toFixed(1)}%)`
      ).join(', ');

      const analysisData = {
        detection_results: { detections: detections },
        analysis_type: 'detection_ingredient_conversion',
        prompt: `다음은 YOLO 객체 탐지로 발견된 항목들입니다. 각 항목을 한글 식재료명으로 변환하고, 같은 식재료는 개수를 합쳐서 정리해주세요.

탐지된 항목들: ${detectionList}

변환 규칙:
- 영어 식재료명을 정확한 한글 식재료명으로 변환
- 같은 식재료가 여러 번 탐지되면 개수를 합쳐서 표시
- 식재료가 아닌 항목은 제외

출력 형식:
사과 3개
브로콜리 1개

지금 변환해주세요:`
      };

      const geminiResponse = await fetch(geminiUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(analysisData),
      });

      if (geminiResponse.ok) {
        const geminiResult = await geminiResponse.json();
        console.log('✅ Gemini Detection 변환 결과:', geminiResult);
        
        const analysisText = geminiResult.analysis || '분석 결과가 없습니다.';
        setGeminiResults(analysisText);

        const newIngredients = parseGeminiIngredientAnalysis(analysisText, detections);
        console.log('🎯 Detection 분석으로 추출된 최종 식재료:', newIngredients);
        
        if (newIngredients.length > 0) {
          mergeIngredientsToFridge(newIngredients);
          setStatusMessage(`AI 변환 완료: ${newIngredients.length}개 식재료 추가`);
        } else {
          setStatusMessage('AI 변환 완료: 추출된 식재료 없음');
        }
      } else {
        throw new Error('Gemini 분석 실패');
      }
    } catch (error) {
      console.error('❌ Gemini 분석 오류:', error);
      setGeminiResults('Detection 분석 실패 - Mock 데이터로 대체');
      
      // 실패 시 영어 탐지 결과를 직접 한글로 변환
      const mockIngredients = convertDetectionsToKorean(detections);
      mergeIngredientsToFridge(mockIngredients);
      setStatusMessage(`Detection 분석 실패 - ${mockIngredients.length}개 식재료 Mock 추가됨`);
    }
  };

  // 영어 탐지 결과를 한글로 직접 변환 (Gemini 실패 시 대안)
  const convertDetectionsToKorean = (detections) => {
    const translationMap = {
      'apple': '사과',
      'banana': '바나나',
      'carrot': '당근',
      'tomato': '토마토',
      'orange': '오렌지',
      'onion': '양파',
      'potato': '감자',
      'cucumber': '오이',
      'lettuce': '상추',
      'broccoli': '브로콜리',
      'pepper': '피망',
      'garlic': '마늘',
      'ginger': '생강',
      'mushroom': '버섯',
      'corn': '옥수수',
      'grape': '포도',
      'strawberry': '딸기',
      'watermelon': '수박',
      'pineapple': '파인애플',
      'lemon': '레몬'
    };

    const countMap = {};
    
    detections.forEach(detection => {
      const koreanName = translationMap[detection.class.toLowerCase()] || detection.class;
      if (countMap[koreanName]) {
        countMap[koreanName].quantity += 1;
        countMap[koreanName].confidence = Math.max(countMap[koreanName].confidence, detection.confidence);
      } else {
        countMap[koreanName] = {
          name: koreanName,
          quantity: 1,
          confidence: detection.confidence,
          source: 'direct_translation'
        };
      }
    });

    return Object.values(countMap).map((item, index) => ({
      id: Date.now() + index,
      ...item
    }));
  };

  // Gemini 분석 결과에서 식재료 파싱
  const parseGeminiIngredientAnalysis = (analysisText, originalDetections) => {
    const ingredients = [];
    let idCounter = 1;

    const lines = analysisText.split('\n').filter(line => line.trim());
    
    lines.forEach(line => {
      const cleanLine = line.trim();
      
      const match = cleanLine.match(/(.+?)\s*(\d+)\s*개/);
      if (match) {
        const [, name, quantity] = match;
        const cleanName = name.trim().replace(/[-•*\d\.\s]/g, '').trim();
        
        if (cleanName && cleanName.length > 0) {
          const relatedDetections = originalDetections.filter(d => 
            analysisText.toLowerCase().includes(d.class.toLowerCase())
          );
          const maxConfidence = relatedDetections.length > 0 
            ? Math.max(...relatedDetections.map(d => d.confidence))
            : 0.8;

          ingredients.push({
            id: idCounter++,
            name: cleanName,
            quantity: parseInt(quantity) || 1,
            confidence: maxConfidence,
            source: 'gemini_analysis'
          });
        }
      }
    });

    return ingredients;
  };

  // OCR 텍스트 분석 결과에서 식재료 파싱
  const parseGeminiOCRAnalysis = (analysisText) => {
    const ingredients = [];
    let idCounter = 1;

    const lines = analysisText.split('\n').filter(line => line.trim());
    
    lines.forEach(line => {
      const cleanLine = line.trim();
      
      let match = cleanLine.match(/(.+?)\s*(\d+)\s*개/);
      if (match) {
        const [, name, quantity] = match;
        let cleanName = name.trim()
          .replace(/입니다$|예요$|이에요$|이다$|다$|네요$|요$/, '')
          .replace(/은$|는$|이$|가$|을$|를$|의$|에$|에서$|로$|으로$/, '')
          .replace(/[-•*\s]+/g, ' ')
          .trim();
        
        if (cleanName && cleanName.length > 0) {
          ingredients.push({
            id: idCounter++,
            name: cleanName,
            quantity: parseInt(quantity) || 1,
            source: 'ocr_gemini_analysis'
          });
          return;
        }
      }
    });

    return ingredients;
  };

  // 서버 연결 테스트
  const testServerConnection = async () => {
    try {
      const healthUrl = `${API_BASE_URL}/health`;
      console.log('🔍 서버 연결 테스트:', healthUrl);
      
      const response = await fetch(healthUrl);
      if (response.ok) {
        const result = await response.json();
        console.log('✅ 서버 연결 성공:', result);
        setStatusMessage('서버 연결 성공');
      } else {
        console.error('❌ 서버 응답 오류:', response.status);
        setStatusMessage(`서버 응답 오류: ${response.status}`);
      }
    } catch (error) {
      console.error('❌ 서버 연결 실패:', error);
      setStatusMessage(`서버 연결 실패: ${error.message} - Mock 모드로 실행 가능`);
    }
  };

  // 홈 화면 렌더링
  if (currentMode === 'home') {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 flex items-center justify-center p-4">
        <div className="w-full max-w-md">
          <div className="text-center mb-8">
            <div className="text-6xl mb-4">🍽️</div>
            <h1 className="text-2xl font-bold text-gray-800 mb-2">
              스마트 푸드 매니저
            </h1>
            <p className="text-gray-600 text-sm">
              AI로 똑똑하게 식사 계획하기
            </p>
          </div>

          <div className="space-y-4">
            <button
              onClick={startHomeCooking}
              className="w-full bg-white rounded-2xl shadow-lg p-6 transition-all duration-300 hover:shadow-xl hover:scale-105 active:scale-95"
            >
              <div className="flex items-center gap-4">
                <div className="bg-green-100 rounded-full p-3">
                  <CookingIcon />
                </div>
                <div className="text-left flex-1">
                  <h3 className="text-lg font-semibold text-gray-800">해먹기</h3>
                  <p className="text-sm text-gray-600">냉장고 식재료로 요리하기</p>
                </div>
                <div className="text-gray-400">→</div>
              </div>
            </button>

            <button
              onClick={startEating}
              className="w-full bg-white rounded-2xl shadow-lg p-6 transition-all duration-300 hover:shadow-xl hover:scale-105 active:scale-95"
            >
              <div className="flex items-center gap-4">
                <div className="bg-orange-100 rounded-full p-3">
                  <EatingIcon />
                </div>
                <div className="text-left flex-1">
                  <h3 className="text-lg font-semibold text-gray-800">사먹기</h3>
                  <p className="text-sm text-gray-600">맛집 추천 및 주문하기</p>
                </div>
                <div className="text-gray-400">→</div>
              </div>
            </button>
          </div>

          <div className="mt-8 text-center">
            <button
              onClick={testServerConnection}
              className="text-sm text-gray-500 hover:text-gray-700 underline"
            >
              서버 연결 테스트
            </button>
          </div>
        </div>
      </div>
    );
  }

  // 사먹기 모드
  if (currentMode === 'eating') {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="text-center">
          <div className="text-6xl mb-4">🚧</div>
          <h2 className="text-xl font-semibold text-gray-800 mb-4">사먹기 기능 개발 중</h2>
          <p className="text-gray-600 mb-6">곧 멋진 기능으로 찾아뵙겠습니다!</p>
          <button
            onClick={goToHome}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
          >
            홈으로 돌아가기
          </button>
        </div>
      </div>
    );
  }

  // 해먹기 모드 메인 화면
  return (
    <div className="min-h-screen bg-gray-50" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
      <div className="w-full max-w-md sm:max-w-2xl lg:max-w-6xl mx-auto p-3 sm:p-4 lg:p-6">
        
        {/* 헤더 */}
        <div className="bg-white rounded-xl shadow-sm p-4 mb-4">
          <div className="flex items-center gap-3 mb-2">
            <button
              onClick={goToHome}
              className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
            >
              <BackIcon />
            </button>
            <CookingIcon />
            <h1 className="text-lg sm:text-xl lg:text-2xl font-bold text-gray-800 truncate">
              해먹기 - 냉장고 식재료 분석
            </h1>
          </div>
          <p className="text-xs sm:text-sm text-gray-600 hidden sm:block ml-12">
            냉장고 사진을 찍어서 식재료를 자동으로 인식해보세요
          </p>
        </div>

        {/* 액션 버튼들 */}
        <div className="bg-white rounded-xl shadow-sm p-4 mb-4">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-4">
            <input
              type="file"
              accept="image/*,.jpg,.jpeg,.png,.bmp,.gif,.webp"
              onChange={handleImageLoad}
              ref={fileInputRef}
              className="hidden"
              multiple={false}
              key={Date.now()}
            />
            
            <button
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center justify-center gap-2 py-3 px-4 bg-blue-600 text-white rounded-lg font-medium transition-all duration-200 active:scale-95 hover:bg-blue-700"
              style={{ minHeight: '48px' }}
            >
              <UploadIcon />
              <span className="text-sm">이미지 업로드</span>
            </button>

            <button
              onClick={runIngredientAnalysis}
              disabled={!currentImage || isProcessing}
              className="flex items-center justify-center gap-2 py-3 px-4 bg-green-600 text-white rounded-lg font-medium transition-all duration-200 active:scale-95 hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed"
              style={{ minHeight: '48px' }}
            >
              {isProcessing ? <LoadingSpinner /> : <BrainIcon />}
              <span className="text-sm">식재료 분석</span>
            </button>
          </div>

          {/* 신뢰도 설정 */}
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2 min-w-fit">
              <SettingsIcon />
              <span className="text-sm font-medium text-gray-700 whitespace-nowrap">신뢰도</span>
            </div>
            <div className="flex-1 px-2">
              <input
                type="range"
                min="0.1"
                max="0.9"
                step="0.1"
                value={confidence}
                onChange={(e) => setConfidence(parseFloat(e.target.value))}
                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer"
                style={{
                  background: `linear-gradient(to right, #3b82f6 0%, #3b82f6 ${((confidence - 0.1) / 0.8) * 100}%, #e5e7eb ${((confidence - 0.1) / 0.8) * 100}%, #e5e7eb 100%)`
                }}
              />
            </div>
            <span className="text-sm font-medium text-gray-600 min-w-[2.5rem] text-center">
              {confidence.toFixed(1)}
            </span>
          </div>
        </div>

        {/* 메인 콘텐츠 */}
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-4">
          
          {/* 이미지 표시 영역 */}
          <div className="lg:col-span-3">
            <div className="bg-white rounded-xl shadow-sm p-4">
              <div 
                className={`border-2 border-dashed rounded-xl min-h-[200px] sm:min-h-[300px] lg:min-h-[400px] flex items-center justify-center transition-all duration-300 cursor-pointer ${
                  isDragOver 
                    ? 'border-blue-500 bg-blue-50' 
                    : 'border-gray-300 hover:border-blue-400 hover:bg-blue-50'
                }`}
                onDragOver={handleDragOver}
                onDragLeave={handleDragLeave}
                onDrop={handleDrop}
                onClick={(e) => {
                  e.preventDefault();
                  fileInputRef.current?.click();
                }}
              >
                {currentImage ? (
                  <img
                    src={currentImage}
                    alt="Uploaded"
                    className="max-w-full max-h-full rounded-lg object-contain"
                    onClick={(e) => e.stopPropagation()}
                    style={{ maxHeight: '60vh' }}
                  />
                ) : (
                  <div className="text-center text-gray-500 p-6">
                    <div className="text-4xl sm:text-5xl mb-3">🧊</div>
                    <p className="text-sm sm:text-base font-medium mb-1">
                      {isDragOver ? '파일을 놓아주세요' : '냉장고 사진을 업로드하세요'}
                    </p>
                    <p className="text-xs sm:text-sm text-gray-400">
                      {isDragOver ? '' : '업로드 후 "식재료 분석" 버튼 클릭'}
                    </p>
                  </div>
                )}
              </div>

              {/* 진행 상태 */}
              {isProcessing && (
                <div className="mt-4 bg-blue-50 border border-blue-200 rounded-lg p-3">
                  <div className="flex items-center gap-3">
                    <LoadingSpinner />
                    <span className="text-blue-800 text-sm font-medium">{processingStep}</span>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* 결과 표시 영역 */}
          <div className="lg:col-span-2">
            {/* 냉장고 속 식재료 대시보드 */}
            <div className="bg-white rounded-xl shadow-sm mb-4">
              <div className="p-4 border-b border-gray-200">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <FridgeIcon />
                    <h3 className="text-lg font-semibold text-gray-800">냉장고 속 식재료</h3>
                  </div>
                  <div className="flex items-center gap-3">
                    <button
                      onClick={() => setFridgeIngredients([])}
                      className="text-xs text-red-500 hover:text-red-700 hover:bg-red-50 px-2 py-1 rounded transition-colors"
                      title="전체 삭제"
                    >
                      전체 삭제
                    </button>
                    <div className="text-sm text-gray-500">
                      총 {fridgeIngredients.length}개
                    </div>
                  </div>
                </div>
              </div>
              <div className="p-4" style={{ minHeight: '250px', maxHeight: '400px', overflowY: 'auto' }}>
                {fridgeIngredients.length > 0 ? (
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {fridgeIngredients.map((ingredient) => (
                      <div key={ingredient.id} className="bg-gradient-to-r from-blue-50 to-green-50 border border-gray-200 rounded-lg p-4 transition-all duration-200 hover:shadow-md">
                        <div className="flex items-center justify-between mb-3">
                          <h4 className="font-semibold text-gray-800 text-lg">{ingredient.name}</h4>
                          <button
                            onClick={() => removeIngredient(ingredient.id)}
                            className="text-red-500 hover:text-red-700 hover:bg-red-50 rounded-full p-1 transition-colors"
                            title="삭제"
                          >
                            <DeleteIcon />
                          </button>
                        </div>
                        
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-3">
                            <button
                              onClick={() => updateIngredientQuantity(ingredient.id, ingredient.quantity - 1)}
                              disabled={ingredient.quantity <= 1}
                              className="w-8 h-8 rounded-full bg-red-100 text-red-600 hover:bg-red-200 disabled:bg-gray-100 disabled:text-gray-400 disabled:cursor-not-allowed flex items-center justify-center transition-colors"
                            >
                              <MinusIcon />
                            </button>
                            
                            <div className="flex flex-col items-center">
                              <span className="text-2xl font-bold text-blue-600">{ingredient.quantity}</span>
                              <span className="text-xs text-gray-500">개</span>
                            </div>
                            
                            <button
                              onClick={() => updateIngredientQuantity(ingredient.id, ingredient.quantity + 1)}
                              className="w-8 h-8 rounded-full bg-green-100 text-green-600 hover:bg-green-200 flex items-center justify-center transition-colors"
                            >
                              <PlusIcon />
                            </button>
                          </div>
                          
                          <div className="text-xs text-gray-500 bg-white bg-opacity-70 px-2 py-1 rounded-full">
                            {ingredient.source === 'ocr_gemini_analysis' && '📄 OCR AI'}
                            {ingredient.source === 'gemini_analysis' && '🧠 AI변환'}
                            {ingredient.source === 'mock_analysis' && '🎭 Mock'}
                            {ingredient.source === 'direct_translation' && '🔄 Direct'}
                            {ingredient.confidence && (
                              <span className="ml-1 text-green-600 font-semibold">
                                {(ingredient.confidence * 100).toFixed(0)}%
                              </span>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center text-gray-500 py-12">
                    <div className="text-4xl mb-4">🥬</div>
                    <h4 className="text-lg font-medium mb-2">냉장고가 비어있습니다</h4>
                    <p className="text-sm">냉장고 사진을 업로드하고 "식재료 분석" 버튼을 클릭하세요</p>
                    <p className="text-xs text-gray-400 mt-2">⚠️ 서버 연결 실패 시 Mock 분석이 동작합니다</p>
                  </div>
                )}
              </div>
              
              {fridgeIngredients.length > 0 && (
                <div className="px-4 py-3 bg-gray-50 border-t border-gray-200 rounded-b-xl">
                  <div className="flex items-center justify-between text-sm">
                    <span className="text-gray-600">총 수량</span>
                    <span className="font-semibold text-gray-800">
                      {fridgeIngredients.reduce((sum, item) => sum + item.quantity, 0)}개
                    </span>
                  </div>
                </div>
              )}
            </div>

            {/* 탭 네비게이션 */}
            <div className="bg-white rounded-xl shadow-sm overflow-hidden">
              <div className="flex border-b border-gray-200">
                <button
                  onClick={() => setActiveTab('detection')}
                  className={`flex-1 py-3 px-2 text-xs sm:text-sm font-medium transition-colors ${
                    activeTab === 'detection' 
                      ? 'bg-blue-50 text-blue-600 border-b-2 border-blue-600' 
                      : 'text-gray-500 hover:text-gray-700'
                  }`}
                >
                  <div className="flex items-center justify-center gap-1">
                    <EyeIcon />
                    <span>탐지</span>
                  </div>
                </button>
                
                <button
                  onClick={() => setActiveTab('ocr')}
                  className={`flex-1 py-3 px-2 text-xs sm:text-sm font-medium transition-colors ${
                    activeTab === 'ocr' 
                      ? 'bg-purple-50 text-purple-600 border-b-2 border-purple-600' 
                      : 'text-gray-500 hover:text-gray-700'
                  }`}
                >
                  <div className="flex items-center justify-center gap-1">
                    <FileTextIcon />
                    <span>OCR</span>
                  </div>
                </button>
                
                <button
                  onClick={() => setActiveTab('gemini')}
                  className={`flex-1 py-3 px-2 text-xs sm:text-sm font-medium transition-colors ${
                    activeTab === 'gemini' 
                      ? 'bg-green-50 text-green-600 border-b-2 border-green-600' 
                      : 'text-gray-500 hover:text-gray-700'
                  }`}
                >
                  <div className="flex items-center justify-center gap-1">
                    <BrainIcon />
                    <span>분석</span>
                  </div>
                </button>
              </div>

              {/* 탭 콘텐츠 */}
              <div className="p-4" style={{ minHeight: '150px', maxHeight: '250px' }}>
                {activeTab === 'detection' && (
                  <div className="h-full overflow-y-auto">
                    <h3 className="text-sm font-semibold text-gray-800 mb-3">식품 탐지 결과</h3>
                    {detectionResults ? (
                      <div className="space-y-2">
                        <div className="text-xs text-gray-600 mb-2">
                          총 {detectionResults.detections?.length || 0}개 탐지
                        </div>
                        {detectionResults.detections?.map((detection, index) => (
                          <div key={index} className="p-2 bg-gray-50 rounded-lg">
                            <div className="flex justify-between items-center">
                              <span className="text-sm font-medium text-blue-600">
                                {detection.class}
                              </span>
                              <span 
                                className={`text-xs font-semibold px-2 py-1 rounded-full ${
                                  detection.confidence > 0.7 ? 'bg-green-100 text-green-700' : 
                                  detection.confidence > 0.4 ? 'bg-yellow-100 text-yellow-700' : 
                                  'bg-red-100 text-red-700'
                                }`}
                              >
                                {(detection.confidence * 100).toFixed(1)}%
                              </span>
                            </div>
                          </div>
                        )) || <p className="text-sm text-gray-500">탐지된 객체가 없습니다.</p>}
                      </div>
                    ) : (
                      <p className="text-sm text-gray-500">탐지 결과가 없습니다.</p>
                    )}
                  </div>
                )}

                {activeTab === 'ocr' && (
                  <div className="h-full overflow-y-auto">
                    <h3 className="text-sm font-semibold text-gray-800 mb-3">OCR 텍스트</h3>
                    <div className="bg-gray-50 rounded-lg p-3 min-h-[100px]">
                      <p className="text-sm text-gray-700 whitespace-pre-wrap break-words leading-relaxed">
                        {ocrResults || '추출된 텍스트가 없습니다.'}
                      </p>
                    </div>
                  </div>
                )}

                {activeTab === 'gemini' && (
                  <div className="h-full overflow-y-auto">
                    <h3 className="text-sm font-semibold text-gray-800 mb-3">Gemini 분석 결과</h3>
                    <div className="bg-gray-50 rounded-lg p-3 min-h-[100px]">
                      <p className="text-sm text-gray-700 whitespace-pre-wrap break-words leading-relaxed">
                        {geminiResults || '분석 결과가 없습니다.'}
                      </p>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* 상태바 */}
        <div className="mt-4 bg-white rounded-xl shadow-sm p-3">
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
            <span className="text-xs sm:text-sm text-gray-700 truncate flex-1">
              {statusMessage}
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FoodDetectionApp;
